import { useEffect, useState } from 'react';

/** Resolves a promise into state, returning a default value until it settles. Can suspend if requested. */
export function usePromise<T>(
  promise: Promise<T> | undefined,
  defaultValue?: undefined,
  suspend?: boolean
): T | undefined;
export function usePromise<T>(promise: Promise<T> | undefined, defaultValue: T, suspend?: boolean): T;

export function usePromise<T>(promise?: Promise<T>, defaultValue?: T, suspend = false): T | undefined {
  const [value, setValue] = useState<T | undefined>(() => defaultValue);

  const resolvedValue = typeof value === 'undefined' ? defaultValue : value;

  useEffect(() => {
    void promise?.then(x => setValue(x));
  }, [promise]);

  if (suspend && promise && typeof resolvedValue === 'undefined') throw promise;

  return resolvedValue;
}
